DROP TABLE IF EXISTS mimiciii_derived.oasis; CREATE TABLE mimiciii_derived.oasis AS
/* ------------------------------------------------------------------ */ /* Title: Oxford Acute Severity of Illness Score (oasis) */ /* This query extracts the Oxford acute severity of illness score. */ /* This score is a measure of severity of illness for patients in the ICU. */ /* The score is calculated on the first day of each ICU patients' stay. */ /* ------------------------------------------------------------------ */ /* Reference for OASIS: */ /*    Johnson, Alistair EW, Andrew A. Kramer, and Gari D. Clifford. */ /*    "A new severity of illness scale using a subset of acute physiology and chronic health evaluation data elements shows comparable predictive accuracy*." */ /*    Critical care medicine 41, no. 7 (2013): 1711-1718. */ /* Variables used in OASIS: */ /*  Heart rate, GCS, MAP, Temperature, Respiratory rate, Ventilation status (sourced FROM `physionet-data.mimiciii_clinical.chartevents`) */ /*  Urine output (sourced from OUTPUTEVENTS) */ /*  Elective surgery (sourced FROM `physionet-data.mimiciii_clinical.admissions` and SERVICES) */ /*  Pre-ICU in-hospital length of stay (sourced FROM `physionet-data.mimiciii_clinical.admissions` and ICUSTAYS) */ /*  Age (sourced FROM `physionet-data.mimiciii_clinical.patients`) */ /* The following views are required to run this query: */ /*  1) urine_output_first_day - generated by urine-output-first-day.sql */ /*  2) vent_first_day - generated by ventilated-first-day.sql */ /*  3) vitals_first_day - generated by vitals-first-day.sql */ /*  4) gcs_first_day - generated by gcs-first-day.sql */ /* Regarding missing values: */ /*  The ventilation flag is always 0/1. It cannot be missing, since VENT=0 if no data is found for vent settings. */ /* Note: */ /*  The score is calculated for *all* ICU patients, with the assumption that the user will subselect appropriate ICUSTAY_IDs. */ /*  For example, the score is calculated for neonates, but it is likely inappropriate to actually use the score values for these patients. */
WITH surgflag AS (
  SELECT
    ie.icustay_id,
    MAX(
      CASE
        WHEN LOWER(curr_service) LIKE '%surg%'
        THEN 1
        WHEN curr_service = 'ORTHO'
        THEN 1
        ELSE 0
      END
    ) AS surgical
  FROM mimiciii.icustays AS ie
  LEFT JOIN mimiciii.services AS se
    ON ie.hadm_id = se.hadm_id AND se.transfertime < ie.intime + INTERVAL '1' DAY
  GROUP BY
    ie.icustay_id
), cohort AS (
  SELECT
    ie.subject_id,
    ie.hadm_id,
    ie.icustay_id,
    ie.intime,
    ie.outtime,
    adm.deathtime,
    CAST(EXTRACT(EPOCH FROM DATE_TRUNC('minute', ie.intime) - DATE_TRUNC('minute', adm.admittime)) / 60 AS BIGINT) AS preiculos,
    CAST(EXTRACT(YEAR FROM ie.intime) - EXTRACT(YEAR FROM pat.dob) AS BIGINT) AS age,
    gcs.mingcs,
    vital.heartrate_max,
    vital.heartrate_min,
    vital.meanbp_max,
    vital.meanbp_min,
    vital.resprate_max,
    vital.resprate_min,
    vital.tempc_max,
    vital.tempc_min,
    vent.vent AS mechvent,
    uo.urineoutput,
    CASE
      WHEN adm.ADMISSION_TYPE = 'ELECTIVE' AND sf.surgical = 1
      THEN 1
      WHEN adm.ADMISSION_TYPE IS NULL OR sf.surgical IS NULL
      THEN NULL
      ELSE 0
    END AS electivesurgery, /* age group */
    CASE
      WHEN CAST(EXTRACT(YEAR FROM ie.intime) - EXTRACT(YEAR FROM pat.dob) AS BIGINT) <= 1
      THEN 'neonate'
      WHEN CAST(EXTRACT(YEAR FROM ie.intime) - EXTRACT(YEAR FROM pat.dob) AS BIGINT) <= 15
      THEN 'middle'
      ELSE 'adult'
    END AS icustay_age_group, /* mortality flags */
    CASE
      WHEN adm.deathtime BETWEEN ie.intime AND ie.outtime
      THEN 1
      WHEN adm.deathtime <= ie.intime /* sometimes there are typographical errors in the death date */
      THEN 1
      WHEN adm.dischtime <= ie.outtime AND adm.discharge_location = 'DEAD/EXPIRED'
      THEN 1
      ELSE 0
    END AS icustay_expire_flag,
    adm.hospital_expire_flag
  FROM mimiciii.icustays AS ie
  INNER JOIN mimiciii.admissions AS adm
    ON ie.hadm_id = adm.hadm_id
  INNER JOIN mimiciii.patients AS pat
    ON ie.subject_id = pat.subject_id
  LEFT JOIN surgflag AS sf
    ON ie.icustay_id = sf.icustay_id
  /* join to custom tables to get more data.... */
  LEFT JOIN mimiciii_derived.gcs_first_day AS gcs
    ON ie.icustay_id = gcs.icustay_id
  LEFT JOIN mimiciii_derived.vitals_first_day AS vital
    ON ie.icustay_id = vital.icustay_id
  LEFT JOIN mimiciii_derived.urine_output_first_day AS uo
    ON ie.icustay_id = uo.icustay_id
  LEFT JOIN mimiciii_derived.ventilation_first_day AS vent
    ON ie.icustay_id = vent.icustay_id
), scorecomp AS (
  SELECT
    co.subject_id,
    co.hadm_id,
    co.icustay_id,
    co.icustay_age_group,
    co.icustay_expire_flag,
    co.hospital_expire_flag, /* Below code calculates the component scores needed for oasis */
    CASE
      WHEN preiculos IS NULL
      THEN NULL
      WHEN preiculos < 10.2
      THEN 5
      WHEN preiculos < 297
      THEN 3
      WHEN preiculos < 1440
      THEN 0
      WHEN preiculos < 18708
      THEN 2
      ELSE 1
    END AS preiculos_score,
    CASE
      WHEN age IS NULL
      THEN NULL
      WHEN age < 24
      THEN 0
      WHEN age <= 53
      THEN 3
      WHEN age <= 77
      THEN 6
      WHEN age <= 89
      THEN 9
      WHEN age >= 90
      THEN 7
      ELSE 0
    END AS age_score,
    CASE
      WHEN mingcs IS NULL
      THEN NULL
      WHEN mingcs <= 7
      THEN 10
      WHEN mingcs < 14
      THEN 4
      WHEN mingcs = 14
      THEN 3
      ELSE 0
    END AS gcs_score,
    CASE
      WHEN heartrate_max IS NULL
      THEN NULL
      WHEN heartrate_max > 125
      THEN 6
      WHEN heartrate_min < 33
      THEN 4
      WHEN heartrate_max >= 107 AND heartrate_max <= 125
      THEN 3
      WHEN heartrate_max >= 89 AND heartrate_max <= 106
      THEN 1
      ELSE 0
    END AS heartrate_score,
    CASE
      WHEN meanbp_min IS NULL
      THEN NULL
      WHEN meanbp_min < 20.65
      THEN 4
      WHEN meanbp_min < 51
      THEN 3
      WHEN meanbp_max > 143.44
      THEN 3
      WHEN meanbp_min >= 51 AND meanbp_min < 61.33
      THEN 2
      ELSE 0
    END AS meanbp_score,
    CASE
      WHEN resprate_min IS NULL
      THEN NULL
      WHEN resprate_min < 6
      THEN 10
      WHEN resprate_max > 44
      THEN 9
      WHEN resprate_max > 30
      THEN 6
      WHEN resprate_max > 22
      THEN 1
      WHEN resprate_min < 13
      THEN 1
      ELSE 0
    END AS resprate_score,
    CASE
      WHEN tempc_max IS NULL
      THEN NULL
      WHEN tempc_max > 39.88
      THEN 6
      WHEN tempc_min >= 33.22 AND tempc_min <= 35.93
      THEN 4
      WHEN tempc_max >= 33.22 AND tempc_max <= 35.93
      THEN 4
      WHEN tempc_min < 33.22
      THEN 3
      WHEN tempc_min > 35.93 AND tempc_min <= 36.39
      THEN 2
      WHEN tempc_max >= 36.89 AND tempc_max <= 39.88
      THEN 2
      ELSE 0
    END AS temp_score,
    CASE
      WHEN UrineOutput IS NULL
      THEN NULL
      WHEN UrineOutput < 671.09
      THEN 10
      WHEN UrineOutput > 6896.80
      THEN 8
      WHEN UrineOutput >= 671.09 AND UrineOutput <= 1426.99
      THEN 5
      WHEN UrineOutput >= 1427.00 AND UrineOutput <= 2544.14
      THEN 1
      ELSE 0
    END AS urineoutput_score,
    CASE WHEN mechvent IS NULL THEN NULL WHEN mechvent = 1 THEN 9 ELSE 0 END AS mechvent_score,
    CASE WHEN electivesurgery IS NULL THEN NULL WHEN electivesurgery = 1 THEN 0 ELSE 6 END AS electivesurgery_score, /* The below code gives the component associated with each score */ /* This is not needed to calculate oasis, but provided for user convenience. */ /* If both the min/max are in the normal range (score of 0), then the average value is stored. */
    preiculos,
    age,
    mingcs AS gcs,
    CASE
      WHEN heartrate_max IS NULL
      THEN NULL
      WHEN heartrate_max > 125
      THEN heartrate_max
      WHEN heartrate_min < 33
      THEN heartrate_min
      WHEN heartrate_max >= 107 AND heartrate_max <= 125
      THEN heartrate_max
      WHEN heartrate_max >= 89 AND heartrate_max <= 106
      THEN heartrate_max
      ELSE CAST((
        heartrate_min + heartrate_max
      ) AS DOUBLE PRECISION) / 2
    END AS heartrate,
    CASE
      WHEN meanbp_min IS NULL
      THEN NULL
      WHEN meanbp_min < 20.65
      THEN meanbp_min
      WHEN meanbp_min < 51
      THEN meanbp_min
      WHEN meanbp_max > 143.44
      THEN meanbp_max
      WHEN meanbp_min >= 51 AND meanbp_min < 61.33
      THEN meanbp_min
      ELSE CAST((
        meanbp_min + meanbp_max
      ) AS DOUBLE PRECISION) / 2
    END AS meanbp,
    CASE
      WHEN resprate_min IS NULL
      THEN NULL
      WHEN resprate_min < 6
      THEN resprate_min
      WHEN resprate_max > 44
      THEN resprate_max
      WHEN resprate_max > 30
      THEN resprate_max
      WHEN resprate_max > 22
      THEN resprate_max
      WHEN resprate_min < 13
      THEN resprate_min
      ELSE CAST((
        resprate_min + resprate_max
      ) AS DOUBLE PRECISION) / 2
    END AS resprate,
    CASE
      WHEN tempc_max IS NULL
      THEN NULL
      WHEN tempc_max > 39.88
      THEN tempc_max
      WHEN tempc_min >= 33.22 AND tempc_min <= 35.93
      THEN tempc_min
      WHEN tempc_max >= 33.22 AND tempc_max <= 35.93
      THEN tempc_max
      WHEN tempc_min < 33.22
      THEN tempc_min
      WHEN tempc_min > 35.93 AND tempc_min <= 36.39
      THEN tempc_min
      WHEN tempc_max >= 36.89 AND tempc_max <= 39.88
      THEN tempc_max
      ELSE CAST((
        tempc_min + tempc_max
      ) AS DOUBLE PRECISION) / 2
    END AS temp,
    UrineOutput,
    mechvent,
    electivesurgery
  FROM cohort AS co
), score AS (
  SELECT
    s.*,
    COALESCE(age_score, 0) + COALESCE(preiculos_score, 0) + COALESCE(gcs_score, 0) + COALESCE(heartrate_score, 0) + COALESCE(meanbp_score, 0) + COALESCE(resprate_score, 0) + COALESCE(temp_score, 0) + COALESCE(urineoutput_score, 0) + COALESCE(mechvent_score, 0) + COALESCE(electivesurgery_score, 0) AS oasis
  FROM scorecomp AS s
)
SELECT
  subject_id,
  hadm_id,
  icustay_id,
  icustay_age_group,
  hospital_expire_flag,
  icustay_expire_flag,
  oasis, /* Calculate the probability of in-hospital mortality */
  CAST(1 AS DOUBLE PRECISION) / (
    1 + EXP(-(
      -6.1746 + 0.1275 * (
        oasis
      )
    ))
  ) AS oasis_PROB,
  age,
  age_score,
  preiculos,
